  isClosedBookInitialTumbleTransformActive() {
    const group = this.closedBookInitialTumbleGroup;
    if (!group)
      return false;
    return Boolean(
      this.closedBookInitialTumbleActive || this.closedBookInitialTumbleResetting || Math.abs(group.rotation.x) > 5e-4 || Math.abs(group.rotation.y) > 5e-4 || Math.abs(group.rotation.z) > 5e-4
    );
  }
  updateClosedBookInitialTumble() {
    const group = this.closedBookInitialTumbleGroup;
    if (!group)
      return;
    if (!this.closedBookInitialTumbleActive) {
      if (this.curPage !== 0 && !this.closedBookInitialTumbleResetting) {
        group.rotation.set(0, 0, 0);
      }
      return;
    }
    if (this.curPage !== 0 || this.backCoverAutoResetActive) {
      this.stopClosedBookInitialTumble({ animate: false, reset: true });
      return;
    }
    if (this.closedBookOpenPreparing) {
      return;
    }
    const elapsed = Math.max(0, (this.time || 0) - (this.closedBookInitialTumbleStartedAt || 0));
    const t2 = elapsed * this.closedBookInitialTumbleSpeed;
    const yaw = t2 * this.closedBookInitialTumbleYawRange;
    const pitchWave = Math.sin(t2 * Math.PI * 2 - 0.35);
    const rollWave = Math.sin(t2 * Math.PI * 2 + Math.PI * 0.42);
    group.rotation.x = this.closedBookInitialTumblePitchBias + pitchWave * this.closedBookInitialTumblePitchRange;
    group.rotation.y = yaw;
    group.rotation.z = this.closedBookInitialTumbleRollBias + rollWave * this.closedBookInitialTumbleRollRange;
  }
